                      borderColor: financeMode ? "rgba(255,255,255,0.08)" : "rgba(148,163,184,0.24)",
                      background: financeMode ? "rgba(255,255,255,0.04)" : "rgba(15,23,42,0.05)",
                      color: financeMode ? "#cbd5e1" : "#475569"
